const webhookData = $('Webhook Trigger').first().json.body || {};
const reportDate = webhookData.date || new Date().toISOString().split('T')[0];
const tickets = Array.isArray($input.first().json) ? $input.first().json : ($input.first().json.data || []);

const agentCosts = {};
const adapterCosts = {};
const projectCosts = {};

const ADAPTER_COST_PER_TICKET = {
  claude_local: 0.50,
  codex_local: 0.40,
  gemini_local: 0.05,
  http: 0.01,
  cursor: 0.45
};

const AGENT_BUDGETS = {
  argus: 10,
  scout: 10
};

for (const ticket of tickets) {
  const agent = ticket.assignee || 'unassigned';
  const adapter = ticket.adapterType || 'claude_local';
  const project = ticket.projectId || ticket.goalId || 'general';
  const cost = ADAPTER_COST_PER_TICKET[adapter] || 0.10;

  if (!agentCosts[agent]) {
    agentCosts[agent] = { totalCost: 0, ticketCount: 0, adapter: adapter };
  }
  agentCosts[agent].totalCost += cost;
  agentCosts[agent].ticketCount += 1;

  if (!adapterCosts[adapter]) {
    adapterCosts[adapter] = { totalCost: 0, ticketCount: 0 };
  }
  adapterCosts[adapter].totalCost += cost;
  adapterCosts[adapter].ticketCount += 1;

  if (!projectCosts[project]) {
    projectCosts[project] = { totalCost: 0, ticketCount: 0 };
  }
  projectCosts[project].totalCost += cost;
  projectCosts[project].ticketCount += 1;
}

const totalCost = Object.values(agentCosts).reduce((sum, a) => sum + a.totalCost, 0);

const warnings = [];
for (const [agent, data] of Object.entries(agentCosts)) {
  const budget = AGENT_BUDGETS[agent];
  if (budget && budget > 0) {
    const utilization = (data.totalCost / budget) * 100;
    if (utilization > 80) {
      warnings.push({
        agent,
        budget,
        spent: Math.round(data.totalCost * 100) / 100,
        utilization: Math.round(utilization),
        severity: utilization >= 100 ? 'critical' : 'warning'
      });
    }
  }
}

const agentBreakdown = Object.entries(agentCosts).map(([name, data]) => ({
  agent: name,
  adapter: data.adapter,
  cost: Math.round(data.totalCost * 100) / 100,
  tickets: data.ticketCount
})).sort((a, b) => b.cost - a.cost);

return [{
  json: {
    reportDate,
    totalCost: Math.round(totalCost * 100) / 100,
    totalTickets: tickets.length,
    agentBreakdown,
    adapterBreakdown: Object.entries(adapterCosts).map(([name, data]) => ({
      adapter: name,
      cost: Math.round(data.totalCost * 100) / 100,
      tickets: data.ticketCount
    })),
    projectBreakdown: Object.entries(projectCosts).map(([name, data]) => ({
      project: name,
      cost: Math.round(data.totalCost * 100) / 100,
      tickets: data.ticketCount
    })),
    warnings,
    hasWarnings: warnings.length > 0
  }
}];

