  "success": true,
  "result": JSON.stringify({ totalCost: $('Aggregate Costs').first().json.totalCost, totalTickets: $('Aggregate Costs').first().json.totalTickets, agentBreakdown: $('Aggregate Costs').first().json.agentBreakdown, warnings: $('Aggregate Costs').first().json.warnings, reportDate: $('Aggregate Costs').first().json.reportDate })
} }];
